import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"时光守护者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/时光守护者.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/时光守护者.md"}'),o={name:"4.资源分区/6.技艺及称号/通用及综合类/时光守护者.md"};function b(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"时光守护者",tabindex:"-1"},[n("时光守护者 "),r("a",{class:"header-anchor",href:"#时光守护者","aria-label":'Permalink to "时光守护者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),s('<h1 id="时光守护者-1" tabindex="-1">时光守护者 <a class="header-anchor" href="#时光守护者-1" aria-label="Permalink to &quot;时光守护者&quot;">​</a></h1><p>时光守护者<br> 称号<br> 魔幻本质</p><p>──这里就是守护者所在.....不对，曾经这里是守护者曾.....不对不对，是有一天这里将会是守护者......等一下，哪里是哪里，现在是什么时间？──</p><p>C+1000</p><p>【时间膨胀】钟楼提供了不可篡改的时间证据，是岛上唯一的可信时间源，但是它的所有者并不可信。<br> 当你进入战斗时，你获得一枚时间戳，这代表着你能操控自身时间的次数，你可以在进行一次攻击或者面对一次攻击时，以一个自由动作使用时间戳，若为攻击中使用，则你的那次攻击可以重新投掷，但是无论如何都要接受之后的结果。若为面对攻击时使用，则使用动作提升为反射动作，你可以使受到的那次攻击重新投掷，无论如何都取之后的结果，若需要，则该重投效果基于闪避防御。之后你失去这枚时间戳，直到战斗结束，在进行一次攻击或者面对一次攻击时最多使用一枚时间戳。<br> 你获得仅能用于下属技艺的2AP。</p><p>下属技艺：</p><p>挥斩<br> D+500<br> 你被斩中了一次……还是没有被斩中？又或者已经被千刀万剐了？<br> 以一个标准动作进行一次近战攻击，这次攻击将会命中触及范围内的全部敌人，你的攻击动作在敌人眼里会严重延迟或者快进，因此这次攻击额外具有高速5。<br> ——额外支付D+500，将该技艺升级为双重挥斩，若你在这次攻击中使用了时间戳，那么在这次攻击中，时间戳的效果改为取较好一次的结果，若你没有在这次攻击中使用时间戳，则你的这次攻击具有融毁5，同时若你此时持有复数的武器，那么在这次攻击中，你可以选择武器伤害取高、攻击范围取低，在攻击时获得加入攻击武器除基本属性外的特性。<br> 在此基础上再额外支付C+2000，将该技艺升级为三重挥斩，若你在这次攻击中使用了时间戳，那么在这次攻击中，你投掷3次攻击骰，随后从中选择较好的2次攻击生效。</p><p>倒计时<br> C+1000<br> 有些村民说他们见过钟楼的指针往反方向转动......但那只是传闻而已....<br> 在战斗开始时，你可以消耗1点意志力来启用倒计时技艺，此时你的脑后会出现一个时钟，其每秒都会倒走一格，每倒走一轮你都会获得2枚时间戳，其会在倒走2轮之后消失，即你最多以此法获得4枚时间戳。</p><p>极速<br> C+1000<br> 看你的背后，我是说……【背后】<br> 以一个整轮动作使用该技艺，你进行一次冲锋攻击，在这次冲锋攻击中，你可以同时击中路径上的全部敌人，这个技艺可以组合在其他冲锋技艺中生效。<br> ——额外支付C+1000，将该技艺升级为真·极速，在使用这个技艺之后，直到你的下一个回合开始前，视作已经进行了一次格挡。</p><p>坠陨之剑<br> B+3000<br> 时钟校准如果有千分之一秒的偏差，都有可能导致带来严重的后果。<br> 以一个整轮动作消耗4点意志力进行一次攻击，随后在当前场景内，你的触及距离扩大至敏感范围的一半。一轮后，你进行攻击所在的位置为圆心，触及范围为半径的区域内会迅速形成一个时间场，处于这一区域内的所有单位会受到B级时空来源的时间延缓效果影响。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
